  // 1. Rate Limiting
  (req, res, next) => {
    rateLimiter.consume(req.ip)
      .then(() => next())
      .catch(() => res.status(429).send('Too Many Requests'));
  },
  // 2. Raw Body for Signature Verification
  bodyParser.raw({ type: 'application/json', limit: '1mb', verify: verifyWebhookSignature }),
  // 3. JSON Parsing and Schema Validation
  (req, res, next) => {
    try {
