      let parsedBody;
      if (typeof req.body === 'string' || Buffer.isBuffer(req.body)) {
          parsedBody = JSON.parse(req.body.toString());
      } else {
          parsedBody = req.body; // Assume already parsed if not buffer/string
      }

      // Validate against schema
      const validationResult = validate(parsedBody, eventSchema);
      if (!validationResult.valid) {
        console.warn("Invalid event schema received:", validationResult.errors);
        return res.status(400).json({ status: "error", message: "Invalid event schema", errors: validationResult.errors.map(e => e.stack) });
      }
      req.parsedBody = parsedBody; // Attach validated body for the handler
      next();
    } catch (e) {
      console.error("Webhook processing error (parsing/validation):", e.message);
      res.status(400).json({ status: "error", message: "Invalid payload or schema validation failed" });
    }
  },
  // 4. Main Request Handler
