function verifyWebhookSignature(req, res, buf, encoding) {
  const signatureHeader = req.headers['x-wdip-signature-sha256'];
  if (!signatureHeader || !signatureHeader.startsWith('sha256=')) {
    throw new Error('Webhook signature missing or invalid format');
  }
  const receivedSignature = signatureHeader.slice(7); // Remove 'sha256='
  try {
    const hmac = crypto.createHmac('sha256', WEBHOOK_SECRET);
    const calculatedDigest = hmac.update(buf).digest('hex');
    // Use Buffer comparison for timing safety, ensure hex strings are compared
    const receivedSigBuffer = Buffer.from(receivedSignature, 'hex');
    const calculatedSigBuffer = Buffer.from(calculatedDigest, 'hex');

    if (receivedSigBuffer.length !== calculatedSigBuffer.length || !crypto.timingSafeEqual(receivedSigBuffer, calculatedSigBuffer)) {
      console.warn("Invalid webhook signature received from IP:", req.ip);
      throw new Error('Webhook signature invalid');
    }
    console.log("Webhook signature verified for request from IP:", req.ip);
  } catch (error) {
    console.error("Error during signature verification:", error);
    throw new Error('Webhook signature verification failed');
  }
}

